// ──────────────────────────────────────────
// BALANCE（傾向の重みとダーク化しきい値）
//   winHarsh = winKind（左右対称）＝“勝ち方そのもの”が結末を決める。
//   useHarsh > useKind ＝ harsh は手数が少ないぶん1回を重く＝“速い＝凶暴に倒れやすい”。
//   pickHarsh/pickKind … 3択で「どの色を選んだか」も人格を少し傾ける（入手の瞬間の選択）。
//   darkenAt … kyoubou がこの値を超えるごとに主人公(ルゥ)の翳り段が +1（0..3）。
//     harsh1戦完走 ≒ pick/use/win で kyoubou ~22 → dark-2 まで翳る。kindは0据え置き＝翳らない。
// ──────────────────────────────────────────
const BALANCE = {
  winHarsh: 10,
  winKind: 10,
  useHarsh: 3,
  useKind: 2,
  pickHarsh: 2,
  pickKind: 2,
  darkenAt: [8, 16, 30],
};

